import java.io.*;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        String userInput = "evilPayload"; // This is the user input that will be deserialized

        try {
            // Convert the user input string to a byte array
            byte[] serializedData = userInput.getBytes();

            // Deserialize the byte array (user input)
            ByteArrayInputStream bis = new ByteArrayInputStream(serializedData);
            ObjectInput in = new ObjectInputStream(bis);
            Object obj = in.readObject();

            // Perform some operation using the deserialized object
            System.out.println("Deserialized object: " + obj.toString());
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

